module RefModule(  
    input clk,  
    input [7:0] audio_in,  
    input [7:0] threshold,  
    output reg [7:0] audio_out  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (audio_in > threshold)  
            audio_out <= audio_in >> 1;  
        else  
            audio_out <= audio_in;  
    end  
endmodule
